from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a written work into a single fluent sentence.
    """
    if not triples:
        return ""

    # Helper to create a phrase for each predicate
    def phrase(t: Triple) -> str:
        s, p, o = t.subject, t.predicate, t.object
        # Common predicates with natural language templates
        if p == "author":
            return f"{s} was written by {o}"
        if p == "isbnNumber":
            return f"its ISBN number is {o}"
        if p == "followedBy":
            return f"is followed by {o}"
        if p == "precededBy":
            return f"is preceded by {o}"
        if p == "language":
            return f"is written in {o}"
        if p == "mediaType":
            return f"its media type is {o}"
        if p == "numberOfPages":
            return f"has {o} pages"
        if p == "country":
            return f"is from {o}"
        if p == "publisher":
            return f"published by {o}"
        if p == "releaseDate":
            return f"was released on {o}"
        if p == "birthDate":
            return f"was born on {o}"
        if p == "genre" or p == "literaryGenre":
            return f"belongs to the {o} genre"
        if p == "capital":
            return f"has capital {o}"
        if p == "leader":
            return f"is led by {o}"
        # Fallback generic phrasing
        return f"{p} {o}"

    # Build phrases for all triples
    phrases = [phrase(t) for t in triples]

    # Combine phrases into a coherent sentence
    if len(phrases) == 1:
        sentence = phrases[0] + "."
    else:
        sentence = "; ".join(phrases) + "."

    return sentence

# EVOLVE-BLOCK-END

